import React, { useEffect, useState } from "react";
import database from "./firebase";
import { ref, set, onValue } from "firebase/database";
import {
  LineChart,
  Line,
  XAxis,
  YAxis,
  CartesianGrid,
  Tooltip,
  Legend,
  ResponsiveContainer,
} from "recharts";
import "./App.css";

function App() {
  const [leftFoot, setLeftFoot] = useState(null);
  const [rightFoot, setRightFoot] = useState(null);
  const [leftFootProcessed, setLeftFootProcessed] = useState([]);

  const handleStart = () => {
    set(ref(database, "commands/recording"), true);
  };

  const handleStop = () => {
    set(ref(database, "commands/recording"), false);
  };

   // --- Listen to recording command ---
   useEffect(() => {
    const commandRef = ref(database, "commands/recording");
    const unsubscribe = onValue(commandRef, (snapshot) => {
      setRecording(snapshot.val() || false);
    });
    return () => unsubscribe();
  }, []);

  // --- Subscribe to left/right foot data from Firebase ---
  useEffect(() => {
    const leftRef = ref(database, "leftFoot");
    const rightRef = ref(database, "rightFoot");

    const unsubscribeLeft = onValue(leftRef, (snapshot) => {
      const data = snapshot.val();
      if (data) {
        const entries = Object.values(data);
        setLeftFoot(entries[entries.length - 1]);
      }
    });

    const unsubscribeRight = onValue(rightRef, (snapshot) => {
      const data = snapshot.val();
      if (data) {
        const entries = Object.values(data);
        setRightFoot(entries[entries.length - 1]);
      }
    });

    return () => {
      unsubscribeLeft();
      unsubscribeRight();
    };
  }, []);

  // --- Update graph history every 0.5s only if recording ---
  useEffect(() => {
    if (!recording) return; // do nothing if recording is false

    const interval = setInterval(() => {
      if (leftFoot) {
        setLeftFootHistory((prev) => {
          const newEntry = {
            timestamp: leftFoot.timestamp,
            raw_x: leftFoot.accel?.x || 0,
            raw_y: leftFoot.accel?.y || 0,
            raw_z: leftFoot.accel?.z || 0,
            // DC-bias removed: subtract mean of current history
            dcb_x:
              leftFoot.accel?.x -
              prev.reduce((sum, p) => sum + p.raw_x, 0) / (prev.length || 1),
            dcb_y:
              leftFoot.accel?.y -
              prev.reduce((sum, p) => sum + p.raw_y, 0) / (prev.length || 1),
            dcb_z:
              leftFoot.accel?.z -
              prev.reduce((sum, p) => sum + p.raw_z, 0) / (prev.length || 1),
          };
          const updated = [...prev, newEntry];
          return updated.slice(-50); // keep last 50 points
        });
      }
    }, 500);

    return () => clearInterval(interval);
  }, [recording, leftFoot]);

  const renderRow = (label, leftValue, rightValue, className = "") => (
    <tr className={`table-row ${className}`}>
      <td className="table-cell label">{label}</td>
      <td className="table-cell">{leftValue ?? "—"}</td>
      <td className="table-cell">{rightValue ?? "—"}</td>
    </tr>
  );

  return (
    <div className="container">
      <div className="content">
        <h1 className="title">
          Wearable Device for Interlimb Asymmetry Detection
        </h1>

        {/* Table + Buttons */}
        <div className="table-button-container">
          <div className="table-wrapper">
            <table className="data-table">
              <thead>
                <tr className="table-header">
                  <th className="header-cell rounded-left">Data</th>
                  <th className="header-cell">Left Foot</th>
                  <th className="header-cell rounded-right">Right Foot</th>
                </tr>
              </thead>
              <tbody>
                {renderRow(
                  "Timestamp",
                  leftFoot?.timestamp,
                  rightFoot?.timestamp
                )}
                {renderRow("Force", leftFoot?.force, rightFoot?.force)}

                <tr className="section-row">
                  <td className="section-cell" colSpan="3">
                    Accelerometer
                  </td>
                </tr>
                {renderRow(
                  "X",
                  leftFoot?.accel?.x,
                  rightFoot?.accel?.x,
                  "indented"
                )}
                {renderRow(
                  "Y",
                  leftFoot?.accel?.y,
                  rightFoot?.accel?.y,
                  "indented"
                )}
                {renderRow(
                  "Z",
                  leftFoot?.accel?.z,
                  rightFoot?.accel?.z,
                  "indented"
                )}

                <tr className="section-row">
                  <td className="section-cell" colSpan="3">
                    Angular Velocity
                  </td>
                </tr>
                {renderRow(
                  "X",
                  leftFoot?.gyro?.x,
                  rightFoot?.gyro?.x,
                  "indented"
                )}
                {renderRow(
                  "Y",
                  leftFoot?.gyro?.y,
                  rightFoot?.gyro?.y,
                  "indented"
                )}
                {renderRow(
                  "Z",
                  leftFoot?.gyro?.z,
                  rightFoot?.gyro?.z,
                  "indented"
                )}
              </tbody>
            </table>
          </div>

          <div className="button-panel">
            <button className="control-button start" onClick={handleStart}>
              Start
            </button>
            <button className="control-button stop" onClick={handleStop}>
              Stop
            </button>
          </div>
        </div>

        {/* GRAPHS */}
        <div className="graph-section">
          <h2 className="graph-title">Left Foot Acceleration - Raw</h2>
          <ResponsiveContainer width="100%" height={300}>
            <LineChart
              data={leftFootProcessed}
              className="line-chart-container"
            >
              <CartesianGrid stroke="#ccc" />
              <XAxis dataKey="timestamp" />
              <YAxis />
              <Tooltip />
              <Legend />
              <Line
                type="monotone"
                dataKey="raw.x"
                stroke="#ff4d4f"
                name="Accel X"
                dot={false}
              />
              <Line
                type="monotone"
                dataKey="raw.y"
                stroke="#52c41a"
                name="Accel Y"
                dot={false}
              />
              <Line
                type="monotone"
                dataKey="raw.z"
                stroke="#1890ff"
                name="Accel Z"
                dot={false}
              />
            </LineChart>
          </ResponsiveContainer><br></br><br></br><br></br>

          <h2 className="graph-title">
            Left Foot Acceleration - DC Bias Removed
          </h2>
          <ResponsiveContainer width="100%" height={300}>
            <LineChart
              data={leftFootProcessed}
              className="line-chart-container"
            >
